import React, { useState } from "react";
import { useParams } from "react-router-dom";
import Navbar from "../../components/Navbar";
import styles from "./UserPages.module.css";

const PackageDetailsPage = () => {
  const { id } = useParams();

  // ⭐ REVIEW STATE
  const [reviews, setReviews] = useState([]);
  const [name, setName] = useState("");
  const [rating, setRating] = useState("⭐ ⭐ ⭐ ⭐ ⭐");
  const [comment, setComment] = useState("");

  // ⭐ HANDLE SUBMIT
  const handleSubmit = () => {
    if (!name || !comment) return;

    const newReview = {
      name,
      rating,
      comment,
    };

    setReviews([newReview, ...reviews]);

    // clear fields
    setName("");
    setComment("");
  };

  return (
    <>
      <Navbar />

      <div className={styles.detailsContainer}>
        
        {/* HERO */}
        <div className={styles.detailsHero}>
          <h1>Romantic Beachfront Goa Retreat</h1>
          <span className={styles.badge}>4 Nights / 5 Days</span>
          <p>
            Experience a romantic getaway along Goa’s stunning beaches with
            premium stays and curated experiences.
          </p>
        </div>

        {/* FEATURES */}
        <div className={styles.detailsGrid}>
          <div className={styles.detailCard}>
            <h3>🚗 Transportation</h3>
            <ul>
              <li>Flights / Trains / Buses</li>
              <li>Airport transfers</li>
              <li>Local travel</li>
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🎡 Sightseeing</h3>
            <ul>
              <li>Tourist attractions</li>
              <li>City tours</li>
              <li>Adventure activities</li>
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🏨 Accommodation</h3>
            <ul>
              <li>Hotel / Resort</li>
              <li>4 Nights stay</li>
            </ul>
          </div>

          <div className={styles.detailCard}>
            <h3>🍽 Meals</h3>
            <ul>
              <li>Breakfast included</li>
              <li>Lunch / Dinner</li>
            </ul>
          </div>
        </div>

        {/* ITINERARY */}
        <div className={styles.itinerary}>
          <h2>🗓 Itinerary</h2>
          <ol>
            <li>Day 1: Arrival</li>
            <li>Day 2: Sightseeing</li>
            <li>Day 3: Activities</li>
            <li>Day 4: Free day</li>
            <li>Day 5: Departure</li>
          </ol>
        </div>

        {/* HOTELS */}
        <h2>🏨 Available Hotels</h2>
        <div className={styles.hotelGrid}>
          <div className={styles.hotelCard}>
            <img src="https://images.unsplash.com/photo-1566073771259-6a8506099945" alt="" />
            <h4>Sea View Resort</h4>
            <p>₹4200</p>
            <button>Select Hotel</button>
          </div>

          <div className={styles.hotelCard}>
            <img src="https://images.unsplash.com/photo-1551882547-ff40c63fe5fa" alt="" />
            <h4>Palm Beach Hotel</h4>
            <p>₹3800</p>
            <button>Select Hotel</button>
          </div>
        </div>

        {/* ⭐ REVIEWS */}
        <div className={styles.reviews}>
          <h2>⭐ Customer Reviews</h2>

          <input
            type="text"
            placeholder="Your Name"
            className={styles.input}
            value={name}
            onChange={(e) => setName(e.target.value)}
          />

          <select
            className={styles.input}
            value={rating}
            onChange={(e) => setRating(e.target.value)}
          >
            <option>⭐ ⭐ ⭐ ⭐ ⭐</option>
            <option>⭐ ⭐ ⭐ ⭐</option>
            <option>⭐ ⭐ ⭐</option>
            <option>⭐ ⭐</option>
            <option>⭐</option>
          </select>

          <textarea
            placeholder="Write your experience..."
            className={styles.textarea}
            value={comment}
            onChange={(e) => setComment(e.target.value)}
          />

          <button className={styles.reviewBtn} onClick={handleSubmit}>
            Submit Review
          </button>

          {/* DISPLAY REVIEWS */}
          {reviews.length === 0 ? (
            <p className={styles.noReview}>No reviews yet.</p>
          ) : (
            <div className={styles.reviewList}>
              {reviews.map((r, index) => (
                <div key={index} className={styles.reviewCard}>
                  <h4>{r.name}</h4>
                  <p>{r.rating}</p>
                  <p>{r.comment}</p>
                </div>
              ))}
            </div>
          )}
        </div>

      </div>
    </>
  );
};

export default PackageDetailsPage;
